INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3000, 1000, "訓練はまだ\nここからですわ", "vo_minigame_1013_icon_2_002_001", "調子が上がって\nきたなっ", 2, 2, 1, "vo_minigame_1013_icon_1_002_001", 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3000, 5000, "クスクス、悪くない\n流れですわね", "vo_minigame_1013_icon_2_003_001", "ほらほら、\nまだいけるだろ？", 2, 2, 2, "vo_minigame_1013_icon_1_003_001", 2);
INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3000, 10000, "すばらしい\n記録ですわ", "vo_minigame_1013_icon_2_004_001", "へへっ、おまえら\nやるじゃねえか！", 2, 2, 3, "vo_minigame_1013_icon_1_004_001", 3);
