INSERT INTO `v1_7a376071877d93b303b1a7449288a3b543243f13917fd9784396cd40f5376376` VALUES (3000, 10000, "まだまだ行きます\nついてきなさい", "vo_minigame_1013_icon_2_005_002", "見てろよ！\nマコト班の快進撃だ！", 2, 3, 5, "vo_minigame_1013_icon_1_005_002", 3);
